parameters.jsCode:
const d = $json;
const BROCHURE_URL = 'https://mirador-villarrica-chatbot-pruebasn8ncub-6852s-projects.vercel.app/brochure/mirador-villarrica-brochure.pdf';
const SHEET_URL = 'https://docs.google.com/spreadsheets/d/1gtqd1Xb6Yr3g3myw0nnJDsnZUSybQYS9aFAEJWaPqhQ/edit?gid=1975618999#gid=1975618999';
const LOCATION_URL = 'https://www.google.com/maps/place/39%C2%B000%2752.4%22S+72%C2%B007%2740.8%22W/@-39.014561,-72.1305769,677m/data=!3m2!1e3!4b1!4m4!3m3!8m2!3d-39.014561!4d-72.128002';
const TOUR_URL = 'https://lanube360.com/mirador-de-villarrica/';

const canal = (d.canal || '').toString().toLowerCase().trim();
if (!['whatsapp', 'email'].includes(canal)) {
  return [{ json: {
    tool_output_text: 'No pude enviar el brochure: el canal debe ser whatsapp o email. Preguntale al lead por cual prefiere recibirlo.',
    success: false,
    is_valid: false,
  } }];
}

const contacto = (d.contacto || '').toString().trim();
if (!contacto) {
  return [{ json: {
    tool_output_text: 'No pude enviar el brochure: falta el dato de contacto. Pide el numero de WhatsApp o correo electronico al lead.',
    success: false,
    is_valid: false,
  } }];
}

const nombre = (d.nombre || 'Cliente').toString().trim();
const recomendacion = (d.recomendacion || '').toString().trim();

let phoneClean = '';
if (canal === 'whatsapp') {
  phoneClean = contacto.replace(/[^0-9]/g, '');
  if (phoneClean.startsWith('9') && phoneClean.length === 9) phoneClean = '56' + phoneClean;
  if (phoneClean.length < 10) {
    return [{ json: {
      tool_output_text: 'El numero de telefono no parece valido. Confirma el numero con el lead e intenta de nuevo.',
      success: false,
      is_valid: false,
    } }];
  }
}

if (canal === 'email') {
  const emailRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  if (!emailRe.test(contacto)) {
    return [{ json: {
      tool_output_text: 'El correo electronico no parece valido. Confirma la direccion con el lead e intenta de nuevo.',
      success: false,
      is_valid: false,
    } }];
  }
}

return [{ json: {
  canal,
  contacto,
  nombre,
  recomendacion,
  phone_clean: phoneClean,
  brochure_url: BROCHURE_URL,
  sheet_url: SHEET_URL,
  location_url: LOCATION_URL,
  tour_url: TOUR_URL,
  is_valid: true,
} }];

const nombre = $('Validate & Prepare').first().json.nombre;
return [{ json: {
  tool_output_text: `Listo, le envie el brochure completo de Mirador de Villarrica por WhatsApp a ${nombre}, junto con el inventario detallado en vivo y una recomendacion personalizada. Hay algo especifico del brochure o las parcelas que le gustaria que le explique?`,
  sent_via: 'whatsapp',
  success: true,
} }];

const nombre = $('Validate & Prepare').first().json.nombre;
return [{ json: {
  tool_output_text: `Listo, le envie el brochure completo de Mirador de Villarrica por correo electronico a ${nombre}, junto con el inventario detallado en vivo y una recomendacion personalizada. Hay algo especifico del brochure o las parcelas que le gustaria que le explique?`,
  sent_via: 'email',
  success: true,
} }];
